from dataclasses import dataclass, field

@dataclass
class ValidationResult:
    is_valid: bool
    errors: list[str] = field(default_factory=list)

class PasswordValidator:
    def validate(self, password: str) -> ValidationResult:
        errors = []
        if len(password) < 8:
            errors.append("Password must be at least 8 characters")
        return ValidationResult(is_valid=len(errors) == 0, errors=errors)
# Run: pytest — PASS

class PasswordValidator:
    MIN_LENGTH = 8

    def __init__(self):
        self.rules = [
            (self._check_length, f"Password must be at least {self.MIN_LENGTH} characters"),
            (self._check_uppercase, "Password must contain at least one uppercase letter"),
            (self._check_lowercase, "Password must contain at least one lowercase letter"),
            (self._check_digit, "Password must contain at least one digit"),
        ]

    def validate(self, password: str) -> ValidationResult:
        errors = [msg for check, msg in self.rules if not check(password)]
        return ValidationResult(is_valid=len(errors) == 0, errors=errors)

    def _check_length(self, p: str) -> bool: return len(p) >= self.MIN_LENGTH
    def _check_uppercase(self, p: str) -> bool: return any(c.isupper() for c in p)
    def _check_lowercase(self, p: str) -> bool: return any(c.islower() for c in p)
    def _check_digit(self, p: str) -> bool: return any(c.isdigit() for c in p)
# Run: pytest — Still PASS
